// Verify HMAC signature từ OpenProject
const crypto = require('crypto');

const secret = $env.OPENPROJECT_WEBHOOK_SECRET;
const signature = $input.first().headers['x-op-signature-256'] || '';
const body = JSON.stringify($input.first().body);

if (secret && signature) {
  const expected = 'sha256=' + crypto
    .createHmac('sha256', secret)
    .update(body)
    .digest('hex');
  if (signature !== expected) {
    throw new Error('Invalid webhook signature');
  }
}

const event = $input.first().body;
const action = event.action || 'unknown';
const wp = event.work_package || {};
const project = wp._links?.project || {};
const assignee = wp._links?.assignee || {};
const author = event._links?.user || {};

// Map action → label dễ đọc
const actionLabel = {
  'work_package:created': '🆕 Work Package mới',
  'work_package:updated': '✏️ Work Package cập nhật',
  'work_package:closed': '✅ Đã đóng',
  'work_package:moved': '↗️ Chuyển project',
  'comment:created': '💬 Comment mới',
  'time_entry:created': '⏱️ Log giờ',
}[action] || `📋 ${action}`;

// Màu theo status/type
const status = wp._links?.status?.title || wp.status || '';
const statusColor = {
  'New': '0078D4',
  'In Progress': 'F7630C',
  'In Review': '8764B8',
  'Closed': '107C10',
  'Rejected': 'D13438',
}[status] || '0078D4';

const wpUrl = `https://openproject.bee.vn/work_packages/${wp.id}`;
const projectUrl = project.href ? `https://openproject.bee.vn${project.href}` : null;

return [{
  json: {
    action,
    actionLabel,
    statusColor,
    wp: {
      id: wp.id,
      subject: wp.subject || '(không có tiêu đề)',
      status,
      type: wp._links?.type?.title || '',
      priority: wp._links?.priority?.title || '',
      dueDate: wp.dueDate || null,
      url: wpUrl,
    },
    project: {
      name: project.title || '',
      url: projectUrl,
    },
    assignee: {
      name: assignee.title || 'Chưa gán',
    },
    actor: {
      name: author.title || 'Hệ thống',
    },
    comment: event.comment?.raw || null,
    changes: event.details || [],
  }
}];

// Build Microsoft Teams Adaptive Card
const d = $input.first().json;

const facts = [];

if (d.wp.type) facts.push({ title: 'Loại', value: d.wp.type });
if (d.wp.status) facts.push({ title: 'Trạng thái', value: d.wp.status });
if (d.wp.priority) facts.push({ title: 'Ưu tiên', value: d.wp.priority });
if (d.assignee.name) facts.push({ title: 'Được gán cho', value: d.assignee.name });
if (d.wp.dueDate) facts.push({ title: 'Deadline', value: d.wp.dueDate });
if (d.project.name) facts.push({ title: 'Project', value: d.project.name });

// Changes detail (cho work_package:updated)
const changeLines = (d.changes || [])
  .filter(c => c.field_name !== 'updated_at')
  .map(c => `**${c.field_name}**: ${c.old_value ?? '—'} → ${c.new_value ?? '—'}`)
  .join('\n\n');

const bodyBlocks = [
  {
    type: 'TextBlock',
    text: d.actionLabel,
    weight: 'Bolder',
    size: 'Medium',
    color: 'Accent',
    wrap: true,
  },
  {
    type: 'TextBlock',
    text: `[#${d.wp.id} — ${d.wp.subject}](${d.wp.url})`,
    wrap: true,
    size: 'Default',
  },
];

if (facts.length > 0) {
  bodyBlocks.push({
    type: 'FactSet',
    facts: facts,
  });
}

if (changeLines) {
  bodyBlocks.push(
    { type: 'TextBlock', text: 'Thay đổi:', weight: 'Bolder', spacing: 'Medium' },
    { type: 'TextBlock', text: changeLines, wrap: true, isSubtle: true }
  );
}

if (d.comment) {
  bodyBlocks.push(
    { type: 'TextBlock', text: 'Comment:', weight: 'Bolder', spacing: 'Medium' },
    { type: 'TextBlock', text: d.comment, wrap: true, isSubtle: true }
  );
}

bodyBlocks.push({
  type: 'TextBlock',
  text: `Bởi: ${d.actor.name}`,
  isSubtle: true,
  spacing: 'Medium',
});

const card = {
  type: 'message',
  attachments: [
    {
      contentType: 'application/vnd.microsoft.card.adaptive',
      content: {
        '$schema': 'http://adaptivecards.io/schemas/adaptive-card.json',
        type: 'AdaptiveCard',
        version: '1.4',
        body: bodyBlocks,
        actions: [
          {
            type: 'Action.OpenUrl',
            title: 'Xem Work Package',
            url: d.wp.url,
          },
        ],
        msteams: {
          width: 'Full',
        },
      },
    },
  ],
};

return [{ json: { card } }];
